<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***ForeignKeyConstraintsFixer*Addallmissingforeignkeyconstraintstoimprovedataintegrity*/require_once__DIR__.'/../core/config.php';require_once__DIR__.'/../core/Database.php';require_once__DIR__.'/APIResponse.php';classForeignKeyFixer{private$pdo;publicfunction__construct(){$db=Database::getInstance();$this->pdo=$db->getConnection();}/***Addallmissingforeignkeyconstraints*/publicfunctionaddMissingConstraints(){$results=[];$errors=[];/Disableforeignkeycheckstemporarily$this->pdo->exec("SETFOREIGN_KEY_CHECKS=0");try{/Addpersonilforeignkeys$results[]=$this->addPersonilConstraints();/Addbagianforeignkeys$results[]=$this->addBagianConstraints();/Addjabatanforeignkeys$results[]=$this->addJabatanConstraints();/Addpersonil_backupforeignkeys$results[]=$this->addPersonilBackupConstraints();}catch(Exception$e){$errors[]="Erroraddingconstraints:".$e->getMessage();}finally{/Re-enableforeignkeychecks$this->pdo->exec("SETFOREIGN_KEY_CHECKS=1");}return['success'=>empty($errors),'results'=>$results,'errors'=>$errors,'timestamp'=>date('c')];}/***Addpersoniltableforeignkeyconstraints*/privatefunctionaddPersonilConstraints(){$constraints=[['name'=>'fk_personil_pangkat','sql'=>"ALTERTABLEpersonilADDCONSTRAINTfk_personil_pangkatFOREIGNKEY(id_pangkat)REFERENCESpangkat(id)ONDELETESETnullONUPDATECASCADE"],['name'=>'fk_personil_jabatan','sql'=>"ALTERTABLEpersonilADDCONSTRAINTfk_personil_jabatanFOREIGNKEY(id_jabatan)REFERENCESjabatan(id)ONDELETESETnullONUPDATECASCADE"],['name'=>'fk_personil_bagian','sql'=>"ALTERTABLEpersonilADDCONSTRAINTfk_personil_bagianFOREIGNKEY(id_bagian)REFERENCESbagian(id)ONDELETESETnullONUPDATECASCADE"],['name'=>'fk_personil_unsur','sql'=>"ALTERTABLEpersonilADDCONSTRAINTfk_personil_unsurFOREIGNKEY(id_unsur)REFERENCESunsur(id)ONDELETESETnullONUPDATECASCADE"],['name'=>'fk_personil_jenis_pegawai','s